(244, 'dsus4-archetype', 'Dsus4', 'D', 'sus4', '', 'archetype', '5432', '', 'archetype-d', 0, 1, '{\"positions\":[{\"string\":4,\"fret\":2,\"finger\":1},{\"string\":5,\"fret\":3,\"finger\":3},{\"string\":6,\"fret\":3,\"finger\":4}],\"barres\":[],\"muted\":[1,2],\"open\":[3]}', 'x,x,R,4,5,R', 'x,x,D,G,A,D', 'Open Dsus4 — creates tension before resolving to D', 1, 118, 0, 1, '2026-03-18 19:50:02', '2026-03-18 19:50:02', 'rootd', 'root', ''),
(245, 'dsus2-archetype', 'Dsus2', 'D', 'sus2', '', 'archetype', '5432', '', 'archetype-d', 0, 1, '{\"positions\":[{\"string\":4,\"fret\":2,\"finger\":1},{\"string\":5,\"fret\":3,\"finger\":3}],\"barres\":[],\"muted\":[1,2],\"open\":[3,6]}', 'x,x,R,2,5,R', 'x,x,D,E,A,D', 'Open Dsus2 — airy, modern sound', 1, 119, 0, 1, '2026-03-18 19:50:02', '2026-03-18 19:50:02', 'rootd', 'root', ''),
(246, 'c-archetype', 'C', 'C', 'maj', '', 'archetype', '5432', '', 'archetype-c', 0, 1, '{\"positions\":[{\"string\":2,\"fret\":3,\"finger\":3},{\"string\":3,\"fret\":2,\"finger\":2},{\"string\":5,\"fret\":1,\"finger\":1}],\"barres\":[],\"muted\":[1],\"open\":[4,6]}', 'x,R,3,5,R,3', 'x,C,E,G,C,E', 'Open C major — the first chord in many songbooks', 1, 120, 0, 1, '2026-03-18 19:50:02', '2026-03-18 19:50:02', 'roota', 'root', ''),
(247, 'cmaj7-archetype', 'Cmaj7', 'C', 'maj7', '', 'archetype', '5432', '', 'archetype-c', 0, 1, '{\"positions\":[{\"string\":2,\"fret\":3,\"finger\":3},{\"string\":3,\"fret\":2,\"finger\":2}],\"barres\":[],\"muted\":[1],\"open\":[4,5,6]}', 'x,R,3,5,7,3', 'x,C,E,G,B,E', 'Open Cmaj7 — lift one finger from C for a lush maj7', 1, 121, 4, 1, '2026-03-18 19:50:02', '2026-03-18 19:50:02', 'roota', 'root', ''),
(248, 'dom7-archetype-roota', 'dom7 archetype (Root A)', 'C', 'dom7', '', 'archetype', '5432', '', 'archetype-c', 1, 1, '{\"positions\":[{\"string\":2,\"fret\":3,\"finger\":3},{\"string\":3,\"fret\":2,\"finger\":2},{\"string\":4,\"fret\":3,\"finger\":4},{\"string\":5,\"fret\":1,\"finger\":1}],\"barres\":[],\"muted\":[1],\"open\":[6]}', 'x,R,3,b7,R,3', 'x,C,E,A#,C,E', 'Open C7 — add the flat 7th for a bluesy dominant sound', 1, 122, 0, 1, '2026-03-18 19:50:02', '2026-03-18 21:01:26', 'roota', 'root', ''),
(249, 'cadd9-archetype', 'Cadd9', 'C', 'add9', '', 'archetype', '5432', '', 'archetype-c', 0, 1, '{\"positions\":[{\"string\":2,\"fret\":3,\"finger\":3},{\"string\":3,\"fret\":2,\"finger\":2},{\"string\":5,\"fret\":3,\"finger\":4}],\"barres\":[],\"muted\":[1],\"open\":[4,6]}', 'x,R,3,5,9,3', 'x,C,E,G,D,E', 'Open Cadd9 — one of the most iconic guitar voicings', 1, 123, 0, 1, '2026-03-18 19:50:02', '2026-03-18 19:50:02', 'roota', 'root', ''),
