INSERT INTO `sbn_chord_progressions` (`id`, `name`, `category`, `numerals`, `description`, `typical_genres`, `tags`, `sort_order`, `featured`, `created_at`, `tonality`, `match_mode`) VALUES
(1, 'The Major Jazz Cadence', 'jazz', 'IIm7,V7,Imaj7', 'The most fundamental progression in jazz. The minor ii chord creates tension that resolves through the dominant V7 to the tonic Imaj7. Mastering this in all 12 keys is essential for any jazz musician.', 'jazz,bossa nova,swing', 'cadence,ii-v-i', 10, 0, '2026-02-26 15:54:33', 'major', 'strict'),
(2, 'The Minor Jazz Cadence', 'jazz', 'IIm7b5,V7,Im', 'The minor-key version of the ii–V–I. The half-diminished ii chord and the altered dominant (V7b9) create a darker, more tense resolution to the minor tonic.', 'jazz,latin', 'cadence,ii-v-i', 20, 0, '2026-02-26 15:54:33', 'minor', 'strict'),
(4, 'Rhythm Changes Bridge', 'jazz', 'III7,VI7,II7,V7', 'The bridge of Rhythm Changes: a chain of dominant 7ths moving through the cycle of 5ths. Each chord is a secondary dominant resolving to the next.', 'jazz,bebop', '', 40, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(5, 'The Turnaround #2', 'jazz', 'I,VI7,IIm7,V7', 'The classic jazz turnaround. The VI is used here as a secondary dominant (V/II), pushing toward the IIm7. Used to cycle back to the top of a form.', 'jazz,standards', 'turnaround', 50, 0, '2026-02-26 15:54:33', 'major', 'strict'),
(6, 'Backdoor Dominant', 'jazz', 'bVII7,Imaj7', 'A substitution where the dominant V7 is replaced by the bVII7 — a chord a half-step above the tonic. Common in jazz and soul; creates a smooth, bluesy resolution.', 'jazz,soul,funk', '', 60, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(7, 'Tritone Substitution Jazz Cadence', 'jazz', 'II,bII,I', 'The dominant V7 is replaced by its tritone substitute (bII7). The bass moves chromatically downward to the tonic, while the voice leading is especially smooth.', 'jazz,bebop', 'chromatic,cadence', 70, 0, '2026-02-26 15:54:33', 'both', 'degree'),
(8, 'The Bill Evans Turnaround', 'jazz', 'Imaj7,bIIImaj7,bVImaj7, bIImaj7', 'A simplified version of John Coltrane''s cycle of major 3rds substitution, dividing the octave symmetrically. Creates rapid harmonic movement with rich inner voice leading.', 'jazz,modern jazz', 'modal interchange', 80, 0, '2026-02-26 15:54:33', 'major', 'strict'),
(9, 'The Extended Turnaround', 'jazz', 'IIIm7,VI7,IIm7,V7', 'An extended turnaround that begins on the iii chord. The IIIm7 and VI7 act as a mini ii–V leading into the main IIm7–V7. Very common in jazz standards.', 'jazz,standards,bossa nova', '', 90, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(10, 'Minor Plagal Cadence', 'jazz', 'IVm,Imaj7', 'A minor IV chord resolving to the major tonic — the \"plagal\" or \"Amen\" cadence with a jazz twist. Creates a melancholic, soulful feel. Common in bossa nova.', 'jazz,bossa nova,soul', '', 100, 0, '2026-02-26 15:54:33', 'major', 'strict'),
(11, 'Parker Blues', 'jazz', 'Imaj7,VIIm7b5,III7,VIm7', 'The opening 4 bars of Charlie Parker''s \"reharmonized\" blues form. The IV minor and the chromatic descent through IIIm7–bIII7 add bebop sophistication to the standard blues.', 'jazz,bebop,blues', 'blues', 110, 0, '2026-02-26 15:54:33', 'major', 'strict'),
(12, '12-Bar Blues', 'blues', 'I7,I7,I7,I7,IV7,IV7,I7,I7,V7,IV7,I7,V7', 'The foundational blues form. 12 bars divided into three 4-bar phrases. The dominant 7th quality on all chords (including the I) gives the blues its characteristic sound.', 'blues,jazz,rock,country', '', 200, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(13, 'Quick-Change Blues', 'blues', 'I7,IV7,I7,I7,IV7,IV7,I7,I7,V7,IV7,I7,V7', 'A variation of the 12-bar blues where bar 2 goes to the IV chord before returning to I. Also called \"quick four.\" Very common in Chicago and Texas blues.', 'blues,jazz', '', 210, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(14, 'Minor Blues', 'blues', 'Im7,Im7,Im7,Im7,IVm7,IVm7,Im7,Im7,V7b9,IVm7,Im7,V7b9', 'The blues in a minor key. The V chord typically carries the altered b9 extension for maximum tension. Used in many jazz standards (e.g., \"Mr. P.C.\", \"Footprints\").', 'jazz,blues', '', 220, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(15, 'I–IV–V', 'blues', 'I7,IV7,V7', 'The core three-chord blues/rock progression. Used in its most direct form in countless songs across blues, rock, country, and folk.', 'blues,rock,country,folk', '', 230, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(16, 'I–V–vi–IV', 'pop', 'I,V,VIm,IV', 'One of the most ubiquitous progressions in popular music. Sometimes called the \"axis progression\" (or \"Pachelbel''s progression\"). Hundreds of hit songs use this pattern.', 'pop,rock', '', 300, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(17, 'vi–IV–I–V', 'pop', 'VIm,IV,I,V', 'A rotation of the I–V–vi–IV, starting on the relative minor. Often used to create a slightly darker or more emotional feel while remaining in a major key.', 'pop,rock', '', 310, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(18, 'I–IV–I–V', 'pop', 'I,IV,I,V', 'A simple, powerful progression that forms the basis of rock and country music. The IV chord adds lift before the V creates tension and returns home.', 'rock,country,pop', '', 320, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(19, 'I–II–III (Ascending)', 'pop', 'I,IIm,IIIm', 'A stepwise ascending bass line progression. Creates a sense of momentum and lift. Used extensively in soft rock and singer-songwriter contexts.', 'pop,rock,soul', '', 330, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(20, 'Perfect Authentic Cadence', 'classical', 'IV,V,I', 'The strongest possible cadence: subdominant to dominant to tonic. The \"amen\" cadence of tonal music. Found in virtually every style from hymns to pop choruses.', 'pop,classical,rock,gospel', '', 340, 0, '2026-02-26 15:54:33', 'both', 'degree'),
(21, 'I–vi–IV–V (50s Progression)', 'pop', 'I,VIm,IV,V', 'Closely related to doo-wop and 1950s rock ''n'' roll. The vi chord adds emotional depth between the tonic and subdominant. Used in countless ballads.', 'pop,rock,doo-wop', '', 350, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(22, 'I–V–IV (Rock)', 'pop', 'I,V,IV', 'A staple of rock and folk music. Moving to V and then down to IV (rather than the \"correct\" IV→V→I order) gives it a raw, driving feel.', 'rock,folk,country', '', 360, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(23, 'Andalusian Cadence (Minor)', 'pop', 'Im,bVII,bVI,V', 'A descending chromatic bass line in a natural minor key. Creates a flamenco/classical feel. Used in rock (Stairway to Heaven, Hit the Road Jack) and Latin music.', 'rock,latin,flamenco,pop', '', 370, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(24, 'I–bVII–IV (Rock)', 'pop', 'I,bVII,IV', 'A common rock/blues-rock progression that borrows the bVII from the Mixolydian/pentatonic scale. Creates a raw, powerful feel without a minor chord.', 'rock,blues rock', '', 380, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(25, 'Dorian Vamp (i–IV)', 'modal', 'Im7,IV7', 'The hallmark of Dorian mode: a minor i chord and a major IV chord (with the raised 6th). Used in countless jazz/fusion pieces (Miles Davis''s \"So What\", Santana).', 'jazz,fusion,rock,latin', '', 400, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(26, 'So What Changes', 'modal', 'Im7,bIIm7', 'From Miles Davis''s \"So What\": 16 bars on D Dorian, then 8 bars on Eb Dorian (a half-step up), then 8 bars back on D. A foundational modal jazz approach.', 'jazz,modal jazz', '', 410, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(27, 'Lydian (I–II)', 'modal', 'Imaj7,IImaj7', 'The characteristic sound of Lydian mode: a major I chord moving to the major II chord (the raised 4th defines the mode). Creates a bright, floating, ethereal feel.', 'jazz,film music,fusion', '', 420, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(28, 'Mixolydian Vamp (I7–bVII)', 'modal', 'I7,bVII', 'The sound of Mixolydian mode: a dominant 7th tonic chord moving to the major chord a whole step below. Blues-inflected, used in rock, funk, and folk.', 'rock,blues,folk,funk', '', 430, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(29, 'Phrygian Cadence', 'modal', 'I,bII', 'The characteristic Phrygian move: minor i to the major chord a half-step above (bII, sometimes called the \"Spanish cadence\" or Neapolitan). Creates a dark, mysterious feel.', 'flamenco,metal,classical', '', 440, 0, '2026-02-26 15:54:33', 'both', 'degree'),
(32, 'Pachelbel Canon', 'classical', 'I,V,VIm,IIIm,IV,I,IV,V', 'The chord sequence from Pachelbel''s Canon in D. This 8-chord pattern and its variations have become perhaps the most recycled progression in all of popular music.', 'classical,pop,rock', '', 600, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(33, 'Circle of Fifths (partial)', 'jazz', 'IIIm7,VI7,IIm7,V7,Imaj7', 'A chain of ii–V relationships moving through the circle of fifths. The entire diatonic cycle of 5ths from iii through to I. Common as a jazz intro or outro.', 'jazz,classical', '', 610, 0, '2026-02-26 15:54:33', 'both', 'strict'),
(34, 'The Jazz Half Cadence', 'jazz', 'IIm7,V7', 'The unresolved ii–V: tension without release. Often used mid-phrase in jazz, or as the last 2 bars of a section that cadences at the top of the next chorus.', 'jazz', 'cadence', 620, 0, '2026-02-26 15:54:34', 'major', 'strict'),
(35, 'Deceptive Cadence', 'classical', 'V7,VIm', 'Instead of resolving V→I, the dominant \"deceives\" by moving to the relative minor vi. Creates surprise and emotional tension. Used to extend phrases.', 'classical', '', 630, 0, '2026-02-26 15:54:34', 'both', 'strict'),
(36, 'Ellington Progression', 'jazz', 'Imaj7, Imaj7, II7, II7, IIm7, V7, Imaj7', '', '', '', 0, 0, '2026-02-26 16:00:50', 'major', 'strict'),
(37, 'Tonic Dominant', 'classical', 'I7, IV', 'The tonic chord is acting as a secondary dominant and resolves to the subdominant chord.', 'jazz, bossa, pop', '', 0, 0, '2026-02-27 21:31:37', 'both', 'strict'),
(38, 'The Turnaround', 'jazz', 'I, VIm, IIm, V7', '', '', '', 0, 0, '2026-03-09 21:27:09', 'major', 'strict'),
(39, 'The Rhythm Changes Progression', 'jazz', 'I, VI7, IIm7, VII7', '', 'jazz, bossa', '', 0, 0, '2026-03-09 21:30:49', 'both', 'strict'),
(41, 'The Corcovado Progression', 'latin', 'Im, VIIo7, bVIIm', '', '', '', 0, 0, '2026-03-09 21:39:35', 'minor', 'strict'),
(42, 'Secondary Dominant II-V', 'jazz', 'II7, V7, I', '', '', '', 0, 0, '2026-03-09 21:44:50', 'both', 'strict'),
(43, 'II-V to relative Major', 'jazz', 'IVm7, bVII7, bIIImaj7', '', '', '', 0, 0, '2026-03-11 13:17:43', 'minor', 'strict'),
(44, 'II-V to relative Minor', 'jazz', 'VIIm7b5, III7, VIm', '', '', '', 0, 0, '2026-03-11 13:45:15', 'major', 'strict'),
(45, 'Minor Blues Cadenza', 'blues', 'bVI, V, I', '', '', 'blues', 0, 0, '2026-03-11 20:15:01', 'both', 'degree');
