CREATE TABLE `sbn_chord_diagrams` (
  `id` INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,
  `slug` TEXT NOT NULL,
  `name` TEXT NOT NULL,
  `root_note` TEXT NOT NULL,
  `quality` TEXT NOT NULL,
  `extensions` TEXT DEFAULT '',
  `voicing_category` TEXT DEFAULT 'drop2',
  `string_set` TEXT DEFAULT '5432',
  `bass_note` TEXT DEFAULT '',
  `shape_family` TEXT DEFAULT '',
  `is_fixed_position` tinyINTEGER DEFAULT 0,
  `start_fret` INTEGER DEFAULT 1,
  `diagram_data` TEXT NOT NULL,
  `interval_labels` TEXT DEFAULT '',
  `notes` TEXT DEFAULT '',
  `description` TEXT DEFAULT NULL,
  `is_default` tinyINTEGER DEFAULT 0,
  `sort_order` INTEGER DEFAULT 0,
  `popularity` INTEGER DEFAULT 0,
  `difficulty` tinyINTEGER DEFAULT 0,
  `created_at` TEXT DEFAULT CURRENT_TIMESTAMP,
  `updated_at` TEXT DEFAULT CURRENT_TIMESTAMP,
  `root_string` TEXT DEFAULT 'roota',
  `inversion` TEXT DEFAULT 'root',
  `alt_names` TEXT DEFAULT ''
);

CREATE TABLE `sbn_chord_diagram_aliases` (
  `id` INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,
  `diagram_id` INTEGER NOT NULL,
  `alt_name` TEXT NOT NULL,
  `alt_root_note` TEXT NOT NULL,
  `alt_quality` TEXT NOT NULL,
  `alt_extensions` TEXT DEFAULT '',
  `alt_bass_note` TEXT DEFAULT '',
  `interval_labels` TEXT DEFAULT '',
  `notes` TEXT DEFAULT '',
  `description` TEXT DEFAULT '',
  `created_at` TEXT DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE `sbn_chord_progressions` (
  `id` INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,
  `name` TEXT NOT NULL DEFAULT '',
  `category` TEXT NOT NULL DEFAULT 'jazz',
  `numerals` TEXT NOT NULL DEFAULT '',
  `description` TEXT DEFAULT NULL,
  `typical_genres` TEXT DEFAULT '',
  `tags` TEXT NOT NULL DEFAULT '',
  `sort_order` INTEGER NOT NULL DEFAULT 0,
  `featured` tinyINTEGER NOT NULL DEFAULT 0,
  `created_at` TEXT DEFAULT CURRENT_TIMESTAMP,
  `tonality` TEXT NOT NULL DEFAULT 'both',
  `match_mode` TEXT NOT NULL DEFAULT 'strict'
);

CREATE TABLE `sbn_leadsheets` (
  `id` INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,
  `title` TEXT NOT NULL,
  `composer` TEXT DEFAULT '',
  `song_key` TEXT DEFAULT 'C',
  `tempo` INTEGER DEFAULT 120,
  `time_signature` TEXT DEFAULT '4/4',
  `rhythm` TEXT DEFAULT '',
  `measure_count` INTEGER DEFAULT 0,
  `description` TEXT DEFAULT NULL,
  `difficulty` TEXT DEFAULT NULL,
  `popularity` TEXT NOT NULL,
  `genre` TEXT DEFAULT NULL,
  `course_id` INTEGER DEFAULT NULL,
  `shortcode_content` TEXT DEFAULT NULL,
  `json_data` TEXT DEFAULT NULL,
  `created_at` TEXT DEFAULT CURRENT_TIMESTAMP,
  `updated_at` TEXT DEFAULT CURRENT_TIMESTAMP,
  `harmony_notes` TEXT DEFAULT NULL,
  `form_notes` TEXT DEFAULT NULL,
  `voicing_notes` TEXT DEFAULT NULL
);

CREATE TABLE `sbn_progression_occurrences` (
  `id` INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,
  `progression_id` INTEGER NOT NULL,
  `leadsheet_id` INTEGER NOT NULL,
  `section_id` TEXT NOT NULL DEFAULT 'A',
  `start_measure` INTEGER NOT NULL DEFAULT 0,
  `length_measures` INTEGER NOT NULL DEFAULT 1,
  `detected_root` TEXT NOT NULL DEFAULT 'C',
  `confidence` REAL NOT NULL DEFAULT 1,
  `created_at` TEXT DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE `sbn_rhythm_patterns` (
  `id` INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,
  `slug` TEXT NOT NULL,
  `name` TEXT NOT NULL,
  `description` TEXT DEFAULT NULL,
  `category` TEXT DEFAULT 'general',
  `time_signature` TEXT DEFAULT '4/4',
  `beats` INTEGER DEFAULT 8,
  `rhythm_pattern` TEXT NOT NULL,
  `thumb_pattern` TEXT DEFAULT '',
  `default_bpm` INTEGER DEFAULT 120,
  `sound` TEXT DEFAULT 'clave',
  `mp3_file` TEXT DEFAULT '',
  `is_default` tinyINTEGER DEFAULT 0,
  `sort_order` INTEGER DEFAULT 0,
  `created_at` TEXT DEFAULT CURRENT_TIMESTAMP,
  `updated_at` TEXT DEFAULT CURRENT_TIMESTAMP,
  `grid_type` TEXT DEFAULT 'sixteenth',
  `perc_sound` TEXT DEFAULT 'none',
  `perc_top` TEXT DEFAULT 'none',
  `perc_bass` TEXT DEFAULT 'none'
);

CREATE TABLE `sbn_voicing_drafts` (
  `id` INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,
  `leadsheet_id` INTEGER NOT NULL,
  `leadsheet_title` TEXT DEFAULT '',
  `chord_name` TEXT NOT NULL,
  `fret_string` TEXT NOT NULL,
  `position` INTEGER DEFAULT 1,
  `fingers` TEXT DEFAULT '',
  `root_note` TEXT DEFAULT '',
  `quality` TEXT DEFAULT '',
  `status` TEXT DEFAULT 'pending',
  `notes` TEXT DEFAULT '',
  `created_at` TEXT DEFAULT CURRENT_TIMESTAMP,
  `updated_at` TEXT DEFAULT CURRENT_TIMESTAMP,
  `bass_note` TEXT DEFAULT ''
);

CREATE TABLE `sbn_voicing_usage` (
  `id` INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,
  `leadsheet_id` INTEGER NOT NULL,
  `chord_diagram_id` INTEGER NOT NULL,
  `chord_name` TEXT NOT NULL,
  `fret_string` TEXT NOT NULL,
  `position` INTEGER DEFAULT 1,
  `root_note` TEXT NOT NULL,
  `quality` TEXT NOT NULL,
  `voicing_category` TEXT DEFAULT '',
  `root_string` TEXT DEFAULT '',
  `inversion` TEXT DEFAULT '',
  `created_at` TEXT DEFAULT CURRENT_TIMESTAMP,
  `bass_note` TEXT DEFAULT '',
  `base_quality` TEXT DEFAULT '',
  `extensions` TEXT DEFAULT '',
  `added_notes` TEXT DEFAULT ''
);

